"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[228],{6442:e=>{e.exports=JSON.parse('{"functions":[{"name":"Destroy","desc":"Destroys the Species object instantly and sets `Opertable` to nil\\n\\n### Example:\\n```lua\\nlocal NPCController = Ecosystem.NewEcosystem(\\"JumpingNPC\\")\\nlocal Specie1 = Ecosystem.NewSpecies(\\"JumpingNPC\\", NPCModel::model)\\n\\n-- The specie object will be unbinded and removed from the Ecosystem Binded objects cache\\nSpecie1:Destroy()\\n\\n```\\n\\n### Or:\\n\\n```lua\\nlocal NPCController = Ecosystem.NewEcosystem(\\"JumpingNPC\\")\\nlocal Specie1 = Ecosystem.NewSpecies(\\"JumpingNPC\\", NPCModel::model)\\n\\n-- The specie object will be unbinded and removed from the Ecosystem Binded objects cache while also destroying the NPCModel\\nSpecie1:Destroy(true)\\n\\n```","params":[{"name":"Nuke","desc":"If instances should be destroyed or dereferenced","lua_type":"Boolean"}],"returns":[{"desc":"","lua_type":"nil"}],"function_type":"method","source":{"line":397,"path":"src/init.luau"}},{"name":"Start","desc":"Starts the FSM runtime for the species called on passing the first StateID as the initial state to run.\\n\\n### Example:\\n```lua\\nlocal NPCController = Ecosystem.NewEcosystem(\\"JumpingNPC\\")\\n\\nNPCController:AddStateAndFeature(\\"Jump10Times\\", function(CurrentSpecies: Ecosystem.Species, StateFrom: string): string\\n\\tlocal Count = 0\\n\\tlocal CurrentObjectHumanoid:Humanoid = CurrentSpecies.ObjectBinded.Humanoid\\n\\n\\twhile task.wait(0.1) do\\n\\t\\tif not CurrentObjectHumanoid.Jump then\\n\\t\\t\\tCurrentObjectHumanoid.Jump = true\\n\\t\\t\\tCount += 1\\n\\t\\tend\\n\\t\\tif Count >= 10 then\\n\\t\\t\\treturn \\"NextState\\" -- The next StateID that should run\\n\\t\\tend\\n\\tend\\nend)\\n\\n-- Freezes the controller making it read-only\\nNPCController:Freeze()\\n\\n-- Creates a Species Class from the Ecosystem template\\nlocal JumpingNPC = Ecosystem.NewSpecies(\\"JumpingNPC\\", NPCInstance)\\n\\n-- Begins cycle\\nJumpingNPC:Start(\\"Jump10Times\\")\\n\\n```","params":[{"name":"StateID","desc":"must be a valid State that was assigned in the ecosystem template","lua_type":"string"}],"returns":[],"function_type":"method","source":{"line":458,"path":"src/init.luau"}},{"name":"Stop","desc":"Stops the current Species runtime instantly by closing the thread\\n\\n### Example:\\n```lua\\nlocal NPCController = Ecosystem.NewEcosystem(\\"JumpingNPC\\")\\nlocal HasJumped10Times = false\\n\\nNPCController:AddStateAndFeature(\\"Jump10Times\\", function(CurrentSpecies: Ecosystem.Species, StateFrom: string): string\\n\\tlocal Count = 0\\n\\tlocal CurrentObjectHumanoid:Humanoid = CurrentSpecies.ObjectBinded.Humanoid\\n\\n\\twhile task.wait(0.1) do\\n\\t\\tif not CurrentObjectHumanoid.Jump then\\n\\t\\t\\tCurrentObjectHumanoid.Jump = true\\n\\t\\t\\tCount += 1\\n\\t\\tend\\n\\t\\tif Count >= 10 then\\n\\t\\t\\tHasJumped10Times = true\\n\\t\\tend\\n\\tend\\nend)\\n\\n-- Freezes the controller making it read-only\\nNPCController:Freeze()\\n\\n-- Creates a Species Class from the Ecosystem template\\nlocal JumpingNPC = Ecosystem.NewSpecies(\\"JumpingNPC\\", NPCInstance)\\n\\n-- Begins cycle\\nJumpingNPC:Start(\\"Jump10Times\\")\\n\\nwhile task.wait() do\\n\\tif HasJumped10Times then\\n\\t\\t-- Stops the running species instantly\\n\\t\\tJumpingNPC:Stop()\\n\\t\\tbreak\\n\\tend\\nend\\n\\n```\\n\\n### Or alternatively:\\n\\n```lua\\nlocal NPCController = Ecosystem.NewEcosystem(\\"JumpingNPC\\")\\n\\nNPCController:AddStateAndFeature(\\"Jump10Times\\", function(CurrentSpecies: Ecosystem.Species, StateFrom: string): string\\n\\tlocal Count = 0\\n\\tlocal CurrentObjectHumanoid:Humanoid = CurrentSpecies.ObjectBinded.Humanoid\\n\\n\\twhile task.wait(0.1) do\\n\\t\\tif not CurrentObjectHumanoid.Jump then\\n\\t\\t\\tCurrentObjectHumanoid.Jump = true\\n\\t\\t\\tCount += 1\\n\\t\\tend\\n\\t\\tif Count >= 10 then\\n\\t\\t\\t-- Returning \\"Stop\\" will cause the running thread to yield and gc\\n\\t\\t\\t-- This method DOES NOT guarantee instant results as it is \\n\\t\\t\\t-- dependent on the current cycle of the GC\\n\\t\\t\\treturn \\"Stop\\"\\n\\t\\tend\\n\\tend\\nend)\\n\\n-- Freezes the controller making it read-only\\nNPCController:Freeze()\\n\\n-- Creates a Species Class from the Ecosystem template\\nlocal JumpingNPC = Ecosystem.NewSpecies(\\"JumpingNPC\\", NPCInstance)\\n\\n-- Begins cycle\\nJumpingNPC:Start(\\"Jump10Times\\")\\n\\n```","params":[],"returns":[],"function_type":"method","source":{"line":574,"path":"src/init.luau"}},{"name":"ForceState","desc":"Forcefully changes the current running state even if a state is mid execution\\n\\n### Example:\\n```lua\\nlocal NPCController = Ecosystem.NewEcosystem(\\"JumpingNPC\\")\\n\\nNPCController:AddStateAndFeature(\\"Jump10Times\\", function(CurrentSpecies: Ecosystem.Species, StateFrom: string): string\\n\\t-- implmentation the same as above\\nend)\\n\\nNPCController:AddStateAndFeature(\\"Wander\\", function(CurrentSpecies: Ecosystem.Species, StateFrom: string): string\\n\\t-- implemtation is user definded\\n\\t-- Ex:\\n\\t-- Makes a NPC wander randomly in a 100x100 box around a fixed point\\nend)\\n\\n-- Freezes the controller making it read-only\\nNPCController:Freeze()\\n\\n-- Creates a Species Class from the Ecosystem template\\nlocal JumpingNPC = Ecosystem.NewSpecies(\\"JumpingNPC\\", NPCInstance)\\n\\n-- Begins cycle\\nJumpingNPC:Start(\\"Jump10Times\\")\\n\\ntask.wait(2)\\n\\n-- Forces the wander state\\nJumpingNPC:ForceState(\\"Wander\\")\\n```\\n### Equal to:\\n```lua\\nlocal JumpingNPC = Ecosystem.NewSpecies(\\"JumpingNPC\\", NPCInstance)\\n\\nJumpingNPC:Start(\\"Jump10Times\\")\\n\\ntask.wait(2)\\n\\nJumpingNPC:ForceState(\\"Wander\\")\\n\\n-- Or Simplily\\n\\nJumpingNPC:Start(\\"Jump10Times\\")\\n\\ntask.wait(2)\\n\\n-- Stops the current state\\nJumpingNPC:Stop()\\n\\n-- CAUTION: Adding a wait my be necessary due to task scheduler priorities\\nJumpingNPC:Start(\\"Wander\\")\\n```","params":[{"name":"StateID","desc":"must be a valid State that was assigned in the ecosystem template","lua_type":"string"}],"returns":[],"function_type":"method","source":{"line":652,"path":"src/init.luau"}},{"name":"GetEnviorment","desc":"Returns the value of a enviorment variable with the given index\\n\\n:::info Read-Only\\nThe `Species` object is **NOT** able to write to `EnviormentVariables`, only read.\\n:::\\n\\n### Example:\\n```lua\\nlocal NPCController = Ecosystem.NewEcosystem(\\"JumpingNPC\\")\\nNPCController:SetFunctionEnviorment(\\"GlobalVariable\\", 10) -- Initial value of 10\\n\\nNPCController:AddStateAndFeature(\\"Jump10Times\\", function(CurrentSpecies: Ecosystem.Species, StateFrom: string): string\\n\\tprint(CurrentSpecies:GetEnviorment(\\"GlobalVariable\\")) -- 10\\n\\tprint(CurrentSpecies:GetEnviorment(\\"GlobalVariable2\\")) -- nil\\n\\tprint(CurrentSpecies:GetEnviorment()) -- The dictionary of enviorment properties\\n\\n\\treturn \\"NextState\\" -- Next state\\nend)\\n\\n```","params":[{"name":"EnvVar","desc":"The index of the enviorment variable","lua_type":"string"}],"returns":[{"desc":"","lua_type":"any"}],"function_type":"method","source":{"line":698,"path":"src/init.luau"}},{"name":"SetProperty","desc":"Updates a internal variable that is local to the species object\\n\\n### Example:\\n```lua\\nlocal NPCController = Ecosystem.NewEcosystem(\\"JumpingNPC\\")\\nNPCController:AddCustomProperty(\\"LocalVariable\\", true) -- Initial value of true\\n\\nNPCController:AddStateAndFeature(\\"Jump10Times\\", function(CurrentSpecies: Ecosystem.Species, StateFrom: string): string\\n\\tprint(CurrentSpecies:GetProperty(\\"LocalVariable\\")) -- true\\n\\tCurrentSpecies:SetProperty(\\"LocalVariable\\", false) -- updates to false\\n\\tprint(CurrentSpecies:GetProperty(\\"LocalVariable\\")) -- false\\n\\n\\t-- Properties must be apart of the template created in the `Ecosystem` object\\n\\tCurrentSpecies:SetProperty(\\"LocalVariable2\\", \\"init\\") -- Error: Attempt to assign nil property\\n\\n\\treturn \\"NextState\\" -- Next state\\nend)\\n\\n```","params":[{"name":"Property","desc":"The index of the local property value","lua_type":"string"},{"name":"Value","desc":"the value to be assigned","lua_type":"any"}],"returns":[],"function_type":"method","source":{"line":745,"path":"src/init.luau"}},{"name":"GetProperty","desc":"Returns the value of a property index or if nil the whole dictionary\\n\\n### Example:\\n```lua\\nlocal NPCController = Ecosystem.NewEcosystem(\\"JumpingNPC\\")\\nNPCController:AddCustomProperty(\\"LocalVariable\\", true) -- Initial value of true\\n\\nNPCController:AddStateAndFeature(\\"Jump10Times\\", function(CurrentSpecies: Ecosystem.Species, StateFrom: string): string\\n\\tprint(CurrentSpecies:GetProperty(\\"LocalVariable\\")) -- true\\n\\tCurrentSpecies:SetProperty(\\"LocalVariable\\", false) -- updates to false\\n\\tprint(CurrentSpecies:GetProperty(\\"LocalVariable\\")) -- false\\n\\n\\tprint(CurrentSpecies:GetProperty()) -- Returns property dictionary\\n\\n\\treturn \\"NextState\\" -- Next state\\nend)\\n\\n```","params":[{"name":"Property","desc":"The index of the local property value","lua_type":"string"}],"returns":[{"desc":"","lua_type":"any"}],"function_type":"method","source":{"line":785,"path":"src/init.luau"}}],"properties":[{"name":"SpeciesID","desc":"The UUID that is assigned when the `Species` object is created ","lua_type":"string","readonly":true,"source":{"line":183,"path":"src/init.luau"}},{"name":"AttachedEcosystemID","desc":"The identifier string that is passes in the `NewSpecies` constructor that matches the `Ecosystem` that you want to bind it to.","lua_type":"string","readonly":true,"source":{"line":190,"path":"src/init.luau"}},{"name":"ClassName","desc":"The class of the object `Species`","lua_type":"string","readonly":true,"source":{"line":197,"path":"src/init.luau"}},{"name":"CurrentState","desc":"The current running state ID `nil` if non is running","lua_type":"string","readonly":true,"source":{"line":204,"path":"src/init.luau"}},{"name":"ObjectBinded","desc":"A optional paramater that allows you to link a instance to the species object","lua_type":"Instance?","readonly":true,"source":{"line":211,"path":"src/init.luau"}},{"name":"_States","desc":"The `States` container that points to the `_States` dictionary of the Ecosystem controller","lua_type":"{ [string]: FunctionState }","private":true,"readonly":true,"source":{"line":219,"path":"src/init.luau"}},{"name":"_InternalProperties","desc":"The `Properties` container that points to the `_InternalProperties` dictionary of the Ecosystem controller __Local to the Species object__","lua_type":"{ [string]: any? }","private":true,"readonly":true,"source":{"line":227,"path":"src/init.luau"}},{"name":"_FunctionEnvVars","desc":"The `Enviorment` container that points to the `_FunctionEnvVars` dictionary of the Ecosystem controller __Global to the Ecosystem object__","lua_type":"{ [string]: any? }","private":true,"readonly":true,"source":{"line":235,"path":"src/init.luau"}},{"name":"_HandlingThread","desc":"The thread that runs the different states stored in `_States`","lua_type":"thread","private":true,"readonly":true,"source":{"line":243,"path":"src/init.luau"}},{"name":"Opertable","desc":"A boolean to check if the `Species` object has been destroyed or not. It is **permenetly** read-only","lua_type":"true?","readonly":true,"source":{"line":250,"path":"src/init.luau"}},{"name":"StateChanged","desc":"A `tram` signal class that fires whenever a State is changed in the order of `(StateFrom:string, StateTo:string)`","lua_type":"Tram<StateFrom:string, StateTo:string)>","tags":["Signal"],"readonly":true,"source":{"line":258,"path":"src/init.luau"}}],"types":[{"name":"Species","desc":"The `Species` object is wrapped inside of the `SecuredClass` this provides protections such as proper read-only properties + more","lua_type":"SecuredClass <Species>","source":{"line":176,"path":"src/init.luau"}}],"name":"Species","desc":"The runtime class of Ecosystem. A specie clones properties from Ecosystem and runs them individually with the ability to share data among other species classes through the [Ecosystem](../Ecosystem/) controller","source":{"line":170,"path":"src/init.luau"}}')}}]);